import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  onSnapshot,
  orderBy,
  query,
  setDoc,
  type Unsubscribe
} from "firebase/firestore";

import { getFirebaseDb } from "@/lib/firebase/client";

export type Category = {
  id: string;
  name: string;
  slug: string;
  visible: boolean;
  order: number;
  createdAt?: number;
  updatedAt?: number;
};

export function listenCategories(onData: (cats: Category[]) => void) {
  const db = getFirebaseDb();
  if (!db) return null;
  const q = query(collection(db, "categories"), orderBy("order", "asc"));
  const unsub: Unsubscribe = onSnapshot(q, (snap) => {
    onData(
      snap.docs.map((d) => ({ id: d.id, ...(d.data() as Omit<Category, "id">) }))
    );
  });
  return unsub;
}

export async function upsertCategory(cat: Omit<Category, "id"> & { id?: string }) {
  const db = getFirebaseDb();
  if (!db) throw new Error("Firestore not configured");
  const now = Date.now();
  const payload = { ...cat, updatedAt: now, createdAt: cat.createdAt ?? now };
  if (cat.id) {
    await setDoc(doc(db, "categories", cat.id), payload, { merge: true });
    return cat.id;
  }
  const created = await addDoc(collection(db, "categories"), payload);
  return created.id;
}

export async function deleteCategory(categoryId: string) {
  const db = getFirebaseDb();
  if (!db) throw new Error("Firestore not configured");
  await deleteDoc(doc(db, "categories", categoryId));
}

